import{_ as e,o as a,c as i,ag as l}from"./chunks/framework-C5-Jzrz4.js";const s=JSON.parse('{"title":"开发规范","description":"当前仓库可落地的代码、接口、提交与文档同步规范","frontmatter":{"title":"开发规范","description":"当前仓库可落地的代码、接口、提交与文档同步规范"},"headers":[],"relativePath":"scripts/guide/06-开发规范.md","filePath":"scripts/guide/06-开发规范.md","lastUpdated":null}');const d=e({name:"scripts/guide/06-开发规范.md"},[["render",function(e,s,d,o,t,c){return a(),i("div",null,[...s[0]||(s[0]=[l('<h1 id="开发规范" tabindex="-1">开发规范 <a class="header-anchor" href="#开发规范" aria-label="Permalink to &quot;开发规范&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本规范基于当前仓库实现，不定义脱离源码的流程。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li><code>apps/web-antd</code> 业务开发</li><li><code>packages</code> 共享能力开发</li><li>文档同步维护</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/package.json</code></li><li>根 <code>package.json</code></li><li><code>apps/web-antd/src/adapter/*</code></li><li><code>apps/web-antd/src/api/*</code></li><li><code>apps/web-antd/src/locales/langs/*</code></li><li><code>internal/lint-configs/*</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="代码与目录约定" tabindex="-1">代码与目录约定 <a class="header-anchor" href="#代码与目录约定" aria-label="Permalink to &quot;代码与目录约定&quot;">​</a></h3><ul><li>路径别名：<code>#/</code> -&gt; <code>apps/web-antd/src/*</code></li><li>API 分层：按业务模块放在 <code>src/api/&lt;domain&gt;/&lt;module&gt;</code></li><li>页面逻辑优先使用 <code>&lt;script setup lang=&quot;ts&quot;&gt;</code></li><li>表单优先走 <code>useVbenForm + 适配器组件</code></li></ul><h3 id="接口与类型约定" tabindex="-1">接口与类型约定 <a class="header-anchor" href="#接口与类型约定" aria-label="Permalink to &quot;接口与类型约定&quot;">​</a></h3><ul><li>API 文件：<code>index.ts</code></li><li>模块类型：<code>model.d.ts</code>（存在即优先复用）</li><li>请求统一使用 <code>alovaInstance</code></li></ul><h3 id="国际化约定" tabindex="-1">国际化约定 <a class="header-anchor" href="#国际化约定" aria-label="Permalink to &quot;国际化约定&quot;">​</a></h3><ul><li>用户可见文案使用 <code>$t(...)</code></li><li>应用语言包维护在 <code>apps/web-antd/src/locales/langs</code></li></ul><h3 id="常用质量命令" tabindex="-1">常用质量命令 <a class="header-anchor" href="#常用质量命令" aria-label="Permalink to &quot;常用质量命令&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:type</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="提交规范" tabindex="-1">提交规范 <a class="header-anchor" href="#提交规范" aria-label="Permalink to &quot;提交规范&quot;">​</a></h3><ul><li>格式：<code>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</code></li><li>常用 type：<code>feat</code>、<code>fix</code>、<code>docs</code>、<code>refactor</code>、<code>chore</code>、<code>test</code></li><li>交互式提交：<code>pnpm commit</code></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>新增功能时先补类型再写页面逻辑，减少后续接口改动成本。</li><li>若修改共享包导出，需要同步应用引用与文档入口。</li><li>文档改动时同步检查 <code>docs/.vitepress/config.mts</code> 和 <code>reference/文档目录.md</code>。</li></ul>',20)])])}]]);export{s as __pageData,d as default};
